module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
parameter ADD = 6'b100000;
parameter ADDU = 6'b100001;
parameter SUB = 6'b100010;
parameter SUBU = 6'b100011;
parameter AND = 6'b100100;
parameter OR = 6'b100101;
parameter XOR = 6'b100110;
parameter NOR = 6'b100111;
parameter SLT = 6'b101010;
parameter SLTU = 6'b101011;
parameter SLL = 6'b000000;
parameter SRL = 6'b000010;
parameter SRA = 6'b000011;
parameter SLLV = 6'b000100;
parameter SRLV = 6'b000110;
parameter SRAV = 6'b000111;
parameter LUI = 6'b001111;
wire signed [31:0] a_signed;
wire signed [31:0] b_signed;
wire signed [32:0] res;
assign a_signed = $signed(a);
assign b_signed = $signed(b);
assign r = res[31:0];
assign zero = (res[31:0] == {32{1'b0}}) ? 1'b1 : 1'b0;
assign carry = (aluc == SUB) ? ((a>=b) ? 1'b0 : 1'b1) : ((res[32] == 1'b1) ? 1'b1 : 1'b0);
assign negative = (res[31] == 1'b1) ? 1'b1 : 1'b0;
assign overflow = (((aluc==ADD)||(aluc==ADDU))&&(a[31]==b[31])&&(a[31]!=res[31])) ? 1'b1 : 1'b0;
assign flag = (aluc==SLT) ? (negative ^ overflow) :
                  (aluc==SLTU) ? (a<b) ? 1'b1 : 1'b0 :
                  1'b0;
assign a_signed = $signed(a);
assign b_signed = $signed(b);
always @(*) begin
    case (aluc)
        ADD: begin
            res = a_signed + b_signed;
        end
        ADDU: begin
            res = a + b;
        end
        SUB: begin
            res = a_signed - b_signed;
        end
        SUBU: begin
            res = a - b;
        end
        AND: begin
            res = a & b;
        end
        OR: begin
            res = a | b;
        end
        XOR: begin
            res = a ^ b;
        end
        NOR: begin
            res = ~(a | b);
        end
        SLT: begin
            res = a_signed < b_signed;
        end
        SLTU: begin
            res = a < b;
        end
        SLL: begin
            res = a << b[4:0];
        end
        SRL: begin
            res = a >> b[4:0];
        end
        SRA: begin
            res = a_signed >>> b[4:0];
        end
        SLLV: begin
            res = a << b[4:0];
        end
        SRLV: begin
            res = a >> b[4:0];
        end
        SRAV: begin
            res = a_signed >>> b[4:0];
        end
        LUI: begin
            res = {a[15:0], 16'b0};
        end
        default: begin
            res = {33{1'bz}};
        end
    endcase
end
endmodule
